import Anthropic from '@anthropic-ai/sdk';

@Injectable() class ChatService:

private static readonly MAX_CONTEXT_MESSAGES = 20;
private static readonly LLM_MODEL = 'claude-sonnet-4-6';
private static readonly MAX_RESPONSE_TOKENS = 1024;
private static readonly SYSTEM_PROMPT = 'Você é um assistente de agendamento médico da plataforma Medicano. Ajude pacientes, clínicas e profissionais com informações sobre consultas, horários e agendamentos. Seja conciso, profissional e responda sempre em português.';

private readonly anthropicClient: Anthropic;

constructor(
  @InjectModel(ChatSession.name) private readonly sessionModel: Model<ChatSessionDocument>,
  @InjectModel(ChatMessage.name) private readonly messageModel: Model<ChatMessageDocument>,
  private readonly configService: ConfigService,
) {
  this.anthropicClient = new Anthropic({
    apiKey: this.configService.get<string>('ANTHROPIC_API_KEY') ?? '',
  });
}

async createSession(dto: CreateSessionDto, userId: string): Promise<ChatSessionDocument>
  - const sessionData: any = { userId: new Types.ObjectId(userId) }
  - if (dto.clinicId) sessionData.clinicId = new Types.ObjectId(dto.clinicId)
  - return this.sessionModel.create(sessionData)

async listSessions(userId: string): Promise<ChatSessionDocument[]>
  - return this.sessionModel.find({ userId: new Types.ObjectId(userId) }).sort({ updatedAt: -1 }).exec()

async sendMessage(sessionId: string, content: string, userId: string): Promise<ChatMessageDocument>
  - const session = await this.findSessionById(sessionId)
  - Save user message: await this.messageModel.create({ sessionId: session._id, role: MessageRole.USER, content })
  - Fetch conversation history: const history = await this.messageModel.find({ sessionId: session._id }).sort({ createdAt: 1 }).limit(ChatService.MAX_CONTEXT_MESSAGES).exec()
  - Build messages array: history.map((msg) => ({ role: msg.role as 'user' | 'assistant', content: msg.content }))
  - Call Anthropic API:
    const response = await this.anthropicClient.messages.create({
      model: ChatService.LLM_MODEL,
      max_tokens: ChatService.MAX_RESPONSE_TOKENS,
      system: ChatService.SYSTEM_PROMPT,
      messages,
    })
  - Extract text: const assistantContent = response.content[0].type === 'text' ? response.content[0].text : ''
  - Save assistant message: const assistantMessage = await this.messageModel.create({ sessionId: session._id, role: MessageRole.ASSISTANT, content: assistantContent })
  - Touch session updatedAt: await this.sessionModel.findByIdAndUpdate(session._id, { updatedAt: new Date() }).exec()
  - return assistantMessage

async listMessages(sessionId: string): Promise<ChatMessageDocument[]>
  - await this.findSessionById(sessionId)
  - return this.messageModel.find({ sessionId: new Types.ObjectId(sessionId) }).sort({ createdAt: 1 }).exec()

private async findSessionById(sessionId: string): Promise<ChatSessionDocument>
  - if (!Types.ObjectId.isValid(sessionId)) throw new NotFoundException('Invalid session ID: ' + sessionId)
  - const session = await this.sessionModel.findById(sessionId).exec()
  - if (!session) throw new NotFoundException('Chat session with ID ' + sessionId + ' not found')
  - return session

